Сразу же после того, как вы совершите действие Уклонение, вы можете позволить одному существу в пределах 60 футов от вас реакцией получить преимущества действия Уклонение.', 'weapon', 'very-rare', null, null, '1-handed', true, 'https://dnd.su/items/2194-sword-of-the-paruns/', 'Guildmasters'' Guide to Ravnica'),
      ('voyager-staff', 'Посох путешественника', 'Вы получаете бонус +1 к броскам атаки и урона, совершённым этим магическим посохом.

Этот посох имеет 10 зарядов. Держа его, вы можете действием израсходовать 1 или более зарядов посоха, для накладывания одного из следующих заклинаний, используя свою Сл: [изгнание [banishment]](/spells/116-banishment/) (4 заряда), [мерцание [blink]](/spells/161-blink/) (3 заряда), [туманный шаг [misty step]](/spells/352-misty_step/) (2 заряда), [создание прохода [passwall]](/spells/327-passwall/) (5 зарядов) или [телепортация [teleport]](/spells/367-teleport/) (7 зарядов).

Посох восстанавливает 1к6 + 4 израсходованных заряда ежедневно на рассвете. Если вы израсходуете последний заряд, бросьте к20. Если выпадет «1», то посох навсегда исчезает.', 'magic-item', 'very-rare', null, null, null, true, 'https://dnd.su/items/2196-voyager-staff/', 'Guildmasters'' Guide to Ravnica')
    ),
    typed_seed as (
      select
        srd_slug::text,
        title_ru::text,
        description_ru::text,
        category::text,
        rarity::text,
        price_gp::numeric,
        weight_lb::numeric,
        slot::text,
        requires_attunement::boolean,
        dndsu_url::text,
        source_detail::text
      from seed
    ),
    inserted as (
      insert into nodes (campaign_id, type_id, title, fields)
      select
        c_rec.id,
        type_id_v,
        s.title_ru,
        jsonb_strip_nulls(jsonb_build_object(
          'srd_slug', s.srd_slug,
          'description', s.description_ru,
          'dndsu_url', s.dndsu_url,
          'source_detail', s.source_detail
        ))
      from typed_seed s
      where not exists (
        select 1 from nodes n
        where n.campaign_id = c_rec.id
          and n.fields->>'srd_slug' = s.srd_slug
      )
      returning id, fields->>'srd_slug' as srd_slug
    )
    insert into item_attributes (
      node_id, category_slug, rarity, price_gp, weight_lb,
      slot_slug, requires_attunement,
      source_slug, availability_slug
    )
    select
      i.id, s.category, s.rarity, s.price_gp, s.weight_lb,
      s.slot, s.requires_attunement,
      'srd-5e', null
    from inserted i
    join typed_seed s on s.srd_slug = i.srd_slug
    on conflict (node_id) do nothing;

    get diagnostics ins_count = row_count;
    raise notice 'Campaign % (%): inserted % new dnd.su items (Guildmasters'' Guide to Ravnica)',
      c_rec.slug, c_rec.id, ins_count;
  end loop;
end $$;

